// Normaliza o evento bruto da Evolution API (messages.upsert) para o
// contrato do Flask POST /api/whatsapp/n8n/inbound.
// Retorna [] (descarta) para eventos que NAO devem virar task:
//   - fromMe (mensagem enviada por nos mesmos)
//   - sem texto (audio/imagem/sticker — Fase 6 trata anexos)
//   - evento que nao seja messages.upsert

const out = [];

for (const item of $input.all()) {
  const body = item.json.body || item.json; // webhook pode aninhar em .body
  const event = (body.event || '').toLowerCase();
  if (event && event !== 'messages.upsert') continue;

  const data = body.data || {};
  const key = data.key || {};
  if (key.fromMe) continue; // ignora o que nos mesmos enviamos

  const remoteJid = key.remoteJid || '';
  const isGroup = remoteJid.endsWith('@g.us');

  // Texto: conversation (simples) ou extendedTextMessage.text (com contexto)
  const msg = data.message || {};
  const text = (
    msg.conversation ||
    (msg.extendedTextMessage && msg.extendedTextMessage.text) ||
    ''
  ).trim();
  if (!text) continue; // sem texto -> ignora (anexos sao Fase 6)

  // Remetente: em grupo e o participant; em DM e o proprio remoteJid.
  const senderJid = isGroup ? (key.participant || '') : remoteJid;
  const sender = senderJid.split('@')[0].replace(/\D/g, '');
  if (!sender) continue;

  // Conversa: grupo mantem o JID @g.us; DM usa o numero.
  const conversation = isGroup ? remoteJid : sender;

  out.push({
    json: {
      sender,
      conversation,
      is_group: isGroup,
      text,
      message_id: key.id || null,
      sender_name: data.pushName || null,
      session_key: body.instance || null
    }
  });
}

return out;
